defmodule MyAppWeb.UserController do
  use MyAppWeb, :controller
  alias MyApp.Accounts
  alias MyApp.Accounts.User
  import MyAppWeb.Auth, only: [authorize_user_update: 2]

  action_fallback MyAppWeb.FallbackController

  def update(conn, %{"id" => id} = params) do
    user = Accounts.get_user!(id)

    # Check authorization
    authorize_user_update(conn.assigns.current_user, user)

    with {:ok, %User{} = user} <- Accounts.update_user(user, user_changeset(user, params)) do
      conn
      |> put_flash(:info, "User updated successfully.")
      |> redirect(to: Routes.user_path(conn, :show, user))
    end
  end

  defp user_changeset(user, params) do
    # Allow only specific fields to be updated
    User.changeset(user, Map.take(params, [:name, :email, :role]))
  end
end

defmodule MyAppWeb.Auth do
  def authorize_user_update(current_user, user) do
    if current_user.id != user.id and not current_user.admin do
      raise MyAppWeb.ErrorHandler.UnauthorizedError
    end
  end
end